+		expect(isGenomeCommand({ kind: "genome-sync", genomePath: "/tmp/g" })).toBe(true);
+	});
+
+	test("returns false for non-genome commands", () => {
+		expect(isGenomeCommand({ kind: "help" })).toBe(false);
