+	emitCommand(cmd: { kind: string; data: Record<string, unknown> }) {
+		this.commands.push(cmd);
+	}
+
+	emitEvent(kind: string, _agentId: string, _depth: number, data: Record<string, unknown>) {
+		this.events.push({ kind, data });
+	}
